#!/usr/bin/env node
// Weekly viral report — analyzes 7-day delta + suggests this week's promotion actions.

import { execSync } from 'node:child_process';
import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname } from 'node:path';

const REPO = process.env.REPO || 'theihtisham/agent-shadow-brain';
const HISTORY_PATH = 'docs/stats-history.json';
const REPORT_PATH = 'docs/weekly-viral-report.md';

function gh(cmd) {
  try { return JSON.parse(execSync(`gh ${cmd}`, { encoding: 'utf-8' })); }
  catch { return null; }
}

let history = [];
if (existsSync(HISTORY_PATH)) {
  try { history = JSON.parse(readFileSync(HISTORY_PATH, 'utf-8')); } catch {}
}

const today = history[history.length - 1] ?? { stars: 0, npm: {} };
const weekAgo = history[Math.max(0, history.length - 8)] ?? today;
const monthAgo = history[Math.max(0, history.length - 31)] ?? today;

const starsDelta7 = today.stars - (weekAgo.stars ?? 0);
const starsDelta30 = today.stars - (monthAgo.stars ?? 0);
const dlDelta7 = (today.npm?.last_week ?? 0) - (weekAgo.npm?.last_week ?? 0);

// Get recent issues + PRs for activity signal
const recentIssues = gh(`api 'repos/${REPO}/issues?state=open&since=${new Date(Date.now() - 7*86400e3).toISOString()}'`) ?? [];
const issueCount = Array.isArray(recentIssues) ? recentIssues.filter(i => !i.pull_request).length : 0;
const prCount = Array.isArray(recentIssues) ? recentIssues.filter(i => i.pull_request).length : 0;

// Top referrer (we can't query private GitHub Insights API, but suggest manual check)

// Suggested actions based on growth state
const suggestions = [];
if (starsDelta7 < 5) {
  suggestions.push('🔥 **Growth low this week** — consider a Show HN re-post or new Reddit submission. Try the cross-tool angle ("the missing layer between Claude Code, Cursor, Cline").');
  suggestions.push('📣 LinkedIn post — your 16K followers are highest-leverage channel. Lead with a specific user benefit, not features.');
}
if (starsDelta7 >= 5 && starsDelta7 < 50) {
  suggestions.push('📈 **Steady growth.** Time to amplify: send to one weekly newsletter (Console.dev, Better Dev Newsletter, AI Tidings, Pointer).');
  suggestions.push('🎬 Make a 60-second screen recording showing `attach-all` lighting up 5 agents. Post to Twitter as standalone.');
}
if (starsDelta7 >= 50) {
  suggestions.push('🚀 **Strong week!** Lock in the momentum: write a "Lessons learned" blog post for dev.to. Tag @theihtisham on every channel.');
  suggestions.push('🤝 Reach out to 3 micro-influencers in the AI coding space — offer a custom demo for their channel.');
}
if (today.npm?.last_week < 100) {
  suggestions.push('📦 **npm downloads low** — add a `quickstart` section to the README at the very top with `npx ...` one-liner.');
}

const report = `# Weekly Viral Report — ${new Date().toISOString().slice(0, 10)}

## 7-Day Snapshot

| Metric | Value | 7d Δ | 30d Δ |
|---|---:|---:|---:|
| ⭐ Stars | **${today.stars}** | ${starsDelta7 >= 0 ? '+' : ''}${starsDelta7} | ${starsDelta30 >= 0 ? '+' : ''}${starsDelta30} |
| 📦 npm dl (week) | ${(today.npm?.last_week ?? 0).toLocaleString()} | ${dlDelta7 >= 0 ? '+' : ''}${dlDelta7} | — |
| 📬 New issues (7d) | ${issueCount} | — | — |
| 🔧 New PRs (7d) | ${prCount} | — | — |

## This Week's Actions

${suggestions.length ? suggestions.map(s => `- ${s}`).join('\n') : '- Steady — keep doing what you\'re doing.'}

## Channels to Hit This Week

- [ ] Twitter/X — 1 thread + 3 standalone tweets with screenshots
- [ ] LinkedIn — 1 long-form post (your 16K followers)
- [ ] Reddit — 1 subreddit post (rotate: r/ClaudeAI → r/LocalLLaMA → r/programming → r/webdev)
- [ ] Discord — drop in 2-3 AI dev communities
- [ ] dev.to — publish or repost an article about a Shadow Brain technique
- [ ] Awesome lists — submit to 1 new awesome-* repo

## Top Stargazers This Week (for thank-you outreach)

Run this to get the list:

\`\`\`
gh api 'repos/${REPO}/stargazers?per_page=20' --jq '.[].login' | head -20
\`\`\`

## Manual Check: GitHub Traffic Insights

The GitHub API doesn't expose traffic data programmatically — but check these manually each week:

- https://github.com/${REPO}/graphs/traffic — referrers + clones
- https://github.com/${REPO}/network/dependents — who's using it

## Raw History

See [\`stats-history.json\`](./stats-history.json) for full timeseries.

---

_Generated by the Viral Amplifier Bot. To customize the suggestion logic, edit \`.github/scripts/weekly-viral-report.mjs\`._
`;

mkdirSync(dirname(REPORT_PATH), { recursive: true });
writeFileSync(REPORT_PATH, report);
console.log(`Weekly report written. ${starsDelta7 >= 0 ? '+' : ''}${starsDelta7} stars this week.`);
